import React from "react";

export default function GoalsScreen({ goals = [] }) {
  return (
    <div className="px-6 pb-24 bg-gray-50 min-h-screen">
      <h1 className="text-2xl font-bold mb-6">Your Goals</h1>
      {goals.length === 0 ? (
        <p className="text-gray-500">No goals yet. Start saving!</p>
      ) : (
        <div className="space-y-4">
          {goals.map((g) => (
            <div
              key={g.id}
              className="bg-white p-4 rounded-xl border border-gray-100 shadow-sm"
            >
              <h2 className="font-semibold text-gray-800">{g.title}</h2>
              <p className="text-sm text-gray-500">{g.description}</p>
              <p className="text-teal-600 font-bold mt-2">
                ${g.amountSaved} / ${g.targetAmount}
              </p>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}
